; 試練の迷宮

name = 試練の迷宮Ｂ４
insideName = Ｂ４
upper = 試練の迷宮Ｂ３
lower = 試練の迷宮Ｂ５
pool = 試練の迷宮Ｂ５
level = 50
bgm = labyrinth
roof = stone
shadow = dark
sky = black
antiWarp = true

; 各パーツ
━ = stoner
　 = marble
☆ = soilr
⃞ = cubew
❑ = cube
❐ = cube
／ = door
☖ = arch
⧻ = fence
︻ = panel
┯ = button
㊤ = ladderu
㊦ = ladderd

; 敵情報
maxGroups = 1
monsters = ゴーストスライム,マジカルスライム,サンダーウィスプ,ミスティック,アークメイジ

; 宝箱
box[1] = ジャンプの巻物,ジャンプの巻物,ジャンプの巻物
box[2] = 罠はない,強者のメダル

